<?php defined('BASEPATH') OR exit('No direct script access allowed');
class Leave extends Manager_Controller {
    public function __construct() { parent::__construct(); $this->load->model('Leave_model'); }
    public function index() { $f=array('status'=>$this->input->get('status')?:'pending','year'=>$this->input->get('year')?:date('Y')); $this->render('manager/leave/index',array('title'=>'อนุมัติการลา','page_title'=>'อนุมัติการลา','requests'=>$this->Leave_model->get_requests($f,50),'leave_types'=>$this->Leave_model->get_types(),'filters'=>$f)); }
    public function approve($id) { $r=$this->Leave_model->get_by_id($id); if($this->Leave_model->approve($id,$this->current_user->user_id,$this->input->post('note',TRUE))&&$r) $this->Notification_model->create(array('user_id'=>$r->user_id,'sender_id'=>$this->current_user->user_id,'type'=>'leave_approved','title'=>'คำขอลาได้รับการอนุมัติ','message'=>'การลาวันที่ '.$r->start_date.' อนุมัติแล้ว','link'=>base_url('employee/leave'))); $this->session->set_flashdata('success','อนุมัติสำเร็จ'); redirect('manager/leave'); }
    public function reject($id) { $r=$this->Leave_model->get_by_id($id); $note=$this->input->post('note',TRUE); if($this->Leave_model->reject($id,$this->current_user->user_id,$note)&&$r) $this->Notification_model->create(array('user_id'=>$r->user_id,'sender_id'=>$this->current_user->user_id,'type'=>'leave_rejected','title'=>'คำขอลาถูกปฏิเสธ','message'=>'การลาวันที่ '.$r->start_date.' ถูกปฏิเสธ'.($note?': '.$note:''),'link'=>base_url('employee/leave'))); $this->session->set_flashdata('warning','ปฏิเสธสำเร็จ'); redirect('manager/leave'); }
}
